            'pricelist_id': self.pricelist_id.id,
            'note': _('Re-order from %s') % self.name,
            'line_ids': line_commands,
        })
        return {
            'type': 'ir.actions.act_window',
            'name': _('Re-order'),
            'res_model': 'pos.lite.order',
            'view_mode': 'form',
            'res_id': new_order.id,
            'target': 'current',
